INSERT INTO `sys_config` VALUES (4, '账号自助-验证码开关', 'sys.account.captchaEnabled', 'true', 'Y', 'admin', '2026-06-29 04:40:02', '', NULL, '是否开启验证码功能（true开启，false关闭）');
