INSERT INTO `sys_oper_log` VALUES (329, '技能节点', 2, 'com.ruoyi.web.controller.skill.SkillNodeController.saveContent()', 'POST', 1, 'admin', '研发部门', '/skill/content', '127.0.0.1', '内网IP', '{\"id\":2,\"path\":\"/apple/DESCRIPTION.md\",\"content\":\"# Apple Skills Package\\n\\n这是一个包含Apple相关技能的技能包。\\n\\n## 包含的技能\\n\\n- **apple-notes**: Apple Notes应用操作\\n- **apple-reminders**: Apple Reminders应用操作\\n-\\n\\n## 作者\\n\\nHermes Agent\\n\\n## 许可证\\n\\nMIT\\n\"} ', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-07-01 02:58:40', 52);
INSERT INTO `sys_oper_log` VALUES (330, '技能节点', 2, 'com.ruoyi.web.controller.skill.SkillNodeController.saveContent()', 'POST', 1, 'admin', '研发部门', '/skill/content', '127.0.0.1', '内网IP', '{\"id\":8,\"path\":\"/skills/apple/apple-reminders/SKILL.md\",\"content\":\"---\\nname: apple-reminders\\ndescription: \\\"Apple Reminders via remindctl: add, list, complete.\\\"\\nversion: 1.0.0\\nauthor: Hermes Agent\\nlicense: MIT\\nplatforms: [macos]\\nmetadata:\\n  hermes:\\n    tags: [Reminders, tasks, todo, macOS, Apple]\\nprerequisites:\\n  commands: [remindctl]\\n---\\n\\n# Apple Reminders Skill\\n\\n通过remindctl命令行工具操作Apple Reminders应用。\\n\\n## 功能特性\\n\\n- 添加新提醒\\n- 列出所有提醒\\n- 标记提醒为已完成\\n- 删除提醒\\n\\n## 使用前提\\n\\n需要安装remindctl命令行工具：\\n\\n```bash\\nbrew install remindctl\\n```\\n\\n## 示例代码\\n\\n```javascript\\nconst { exec } = require(\'child_process\');\\n\\nfunction addReminder(title, dueDate) {\\n  const cmd = `remindctl add \\\"${title}\\\" --due \\\"${dueDate}\\\"`;\\n  exec(cmd, (error, stdout, stderr) => {\\n    if (error) {\\n      console.error(`Error: ${error.message}`);\\n      return;\\n    }\\n    console.log(`Reminder added: ${stdout}`);\\n  });\\n}\\n\\nfunction listReminders() {\\n  exec(\'remindctl list\', (error, stdout, stderr) => {\\n    if (error) {\\n      console.error(`Error: ${error.message}`);\\n      return;\\n    }\\n    console.log(stdout);\\n  });\\n}\\n```\\n\\n## 支持的平台\\n\\n- macOS 10.15+\\n\\n## 相关技能\\n\\n参考: @file[apple-notes](../apple-notes/SKILL.md)\\n\"} ', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-07-01 03:08:28', 49);
