INSERT INTO `sys_oper_log` VALUES (423, '技能节点', 2, 'com.ruoyi.web.controller.skill.SkillNodeController.saveContent()', 'POST', 1, 'admin', '研发部门', '/skill/content', '127.0.0.1', '内网IP', '{\"id\":56,\"path\":\"/BIMS/human-genetic-declaration-skill-1.0/SKILL.md\",\"content\":\"---\\nname: 人类遗传ISO20387书写规范\\ndescription: \\\"人类遗传ISO20387书写规范\\\"\\nversion: 1.0.0\\nauthor: Wang：human-genetic-declaration\\ndescription：全套工具包，用于辅助医疗机构、科研院所完成人类遗传资源保藏审批申报工作。适用于用户需要协助完成保藏审批申报材料相关工作的场景，包括：（1）对现有样本库管理体系文件开展差距分析；（2）编制保藏方案；（3）制定保藏管理制度与标准操作技术规范；（4）编制知情同意书与合法来源证明；（5）解读《人类遗传资源管理条例》及保藏审批指南要求；（6）排查保藏审批所需的缺失文件。当用户提及人类遗传资源、保藏审批、样本库建设、伦理审查、知情同意等关键词时，也可使用本工具包。\\n---\\nChange Log： \\n| version | updateOn | author | modification |\\n|------|------|--------|---------|\\n| Alpha_V3.0 | 2026-06-09 | AI助手 | 初始版本 |\\n\\n# 生物样本库人遗申报文件助手\\n\\n## 概述\\n\\n### 1. 工具描述\\n本工具助力医疗机构、科研院所及生物样本库建设单位高效完成人类遗传资源保藏审批申报工作，提供配套工具、模板、参考资料与指导方案，支持各类申报文件的编制、审核及合规性差距分析工作。\\n\\n### 2. 目标用户\\n医疗机构生物样本库管理人员、科研项目负责人、伦理委员会秘书、申报材料编写人员。\\n\\n### 3. 使用前提\\n用户应具备基本的样本库管理知识，了解《人类遗传资源管理条例》的基本要求。建议在使用前先阅读《人类遗传资源管理条例》原文及保藏审批指南。\\n\\n### 4. 本工具包含内容\\n- 申报要求详解指引\\n- 所有申报文件模板\\n- 模板内容预览（含各核心文件模板完整结构）\\n- 分步式文件编制指导\\n- 现有申报文件差距分析\\n- 缺失文件识别\\n- 合规性核查清单\\n\\n### 5. 使用场景\\n- 启动人类遗传资源保藏审批申报工作\\n- 编制或更新保藏方案、管理制度、技术规范等申报文件\\n- 从非标准化管理过渡至合规的样本库管理体系\\n- 依据《人类遗传资源管理条例》及保藏审批指南开展差距分析\\n- 依据伦理审查、知情同意、样本溯源等要求，完成文件审查与适配\\n- 筹备保藏审批现场评审及模拟答辩\\n\\n---\\n## 快速启动检查表（10步完成申报准备）\\n\\n> 本清单适用于初次使用本技能包的用户，按顺序完成即可覆盖90%的准备工作。\\n1. **阅读法规**：通读 `references/human-genetic-resources-regulations.md`（30分钟）\\n2. **收集现有文件**：整理已有申报资料放入一个文件夹，包括但不限于法人资格证书、样本库保藏方案、样本库保藏管理制度、样本库标准操作技术规范汇编、样本库平面布局图、知情同意书、伦理审查批件、合法来源证明等\\n3. **运行差距分析**：使用 `gap_analyzer.py` 或向AI提供文件清单，获取缺失项报告\\n4. **回答信息收集问卷**：向AI提供生物样本库基础信息，包括单位全称、门诊量、设备型号、人员信息等（见“信息收集”章节）\\n5. **生成核心文件**：按优先级让AI生成初稿，包括样本库保藏方案、样本库保藏管理制度、样本库标准操作技术规范汇编、合法来源证明等\\n6. **获取伦理批件**：将保藏方案和知情同意书提交伦理委员会，拿到正式批件\\n7. **补充运行记录**：准备培训记录、设备校准报告、环境监控日志等（至少6个月）\\n8. **跨文件一致性检查**：运行 `consistency_checker.py` 修正矛盾项\\n9. **提交与答辩**：线上填报，模拟评审问答（见附录），参加现场评审\\n\\n---\\n\\n## 核心工作流程\\n\\n### 一、现状评估（差距分析）\\n\\n#### 适用场景\\n\\n申报单位已有部分人遗申报文件（如保藏方案、知情同意书、管理制度、技术规范等），需排查与保藏审批要求的差距，识别缺失项与不合规项。\\n\\n#### 执行流程\\n1. **收集现有文件**\\n    - 请用户提供当前人遗申报文件目录和文件\\n    - 支持格式：.doc、.docx、.pdf\\n    - 涵盖范围：生物样本库保藏申请书、单位法人资格证书或营业执照、样', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-07-03 07:20:03', 187);
