INSERT INTO `sys_oper_log` VALUES (470, '技能节点', 1, 'com.ruoyi.web.controller.skill.SkillNodeController.createFile()', 'POST', 1, 'admin', '研发部门', '/skill/file', '127.0.0.1', '内网IP', '{\"content\":\"---\\nname: SKILL\\ndescription: \\\"SKILL文档说明\\\"\\nversion: 1.0.0\\nauthor: Unknown\\ndate: 2026-07-06\\n---\\n\\n# SKILL\\n\\n文档内容\\n\\n## 简介\\n\\n在此填写文档内容...\\n\\n## 详细说明\\n\\n### 小节1\\n\\n内容...\\n\\n### 小节2\\n\\n内容...\\n\\n## 参考资料\\n\\n- 参考链接1\\n- 参考链接2\\n\",\"createBy\":\"admin\",\"createTime\":\"2026-07-06 10:43:44\",\"fileExtension\":\".md\",\"fileSize\":279,\"id\":73,\"isDirectory\":false,\"mimeType\":\"text/markdown\",\"name\":\"SKILL.md\",\"nodeType\":\"file\",\"params\":{},\"parentId\":72,\"path\":\"/BIMS/bims-base-permission/SKILL.md\",\"skillMetadata\":\"{\\\"name\\\":\\\"SKILL\\\",\\\"description\\\":\\\"SKILL文档说明\\\",\\\"version\\\":\\\"1.0.0\\\",\\\"author\\\":\\\"Unknown\\\",\\\"date\\\":\\\"2026-07-06\\\"}\",\"sortOrder\":0} ', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-07-06 02:43:44', 39);
INSERT INTO `sys_oper_log` VALUES (471, '技能节点', 2, 'com.ruoyi.web.controller.skill.SkillNodeController.saveContent()', 'POST', 1, 'admin', '研发部门', '/skill/content', '127.0.0.1', '内网IP', '{\"id\":73,\"path\":\"/BIMS/bims-base-permission/SKILL.md\",\"content\":\"---\\nname: \\\"bims-base-permission\\\"\\ndescription: \\\"⚠️ 强制执行：所有查询必须先调用本Skill。本Skill是唯一权限入口，不可绕过。AI必须先获取用户权限，再执行任何数据库查询。违反此规则将导致数据泄露。\\\"\\nversion: 1.0.0\\n---\\n\\n# Skill：数据权限基础服务\\n\\n## 一、 ⚠️ 强制执行规则（最高优先级）\\n\\n**本 Skill 是数据权限的唯一入口，任何数据库查询都必须在获取权限条件后才能执行。**\\n\\n### 1.1 执行顺序（强制，不可调换）\\n\\n```\\n用户发起查询请求\\n        ↓\\n  第1步：调用 bims-base-permission Skill（本 Skill）\\n        ↓\\n  获取权限过滤条件（user_type、tenant_id、project_id 列表）\\n        ↓\\n  第2步：调用 bims-business-query Skill\\n        ↓\\n  确认查询路径存在 + 组合权限条件\\n        ↓\\n  第3步：生成 SQL 并执行\\n\\n```\\n\\n### 1.2 禁止行为清单\\n\\n| 序号 | 禁止行为                         | 违规示例                                                     | 正确做法                                |\\n| :--: | -------------------------------- | ------------------------------------------------------------ | --------------------------------------- |\\n|  1   | **跳过本 Skill 直接查数据库**    | 用户问\\\"有多少项目\\\"，直接执行 `SELECT COUNT(*) FROM project_info` | 先调用本 Skill 获取权限条件，再查       |\\n|  2   | **在权限条件获取前执行业务查询** | 先调业务 Skill，再补权限条件                                 | 严格执行：权限 → 业务 → 查询            |\\n|  3   | **合并两个 Skill 的执行步骤**    | \\\"权限和业务一起查就行\\\"                                       | 严格按顺序：先权限 → 再业务             |\\n|  4   | **以\\\"数据库能读\\\"为由绕过约束**   | \\\"这个查询很简单，直接查一下就好\\\"                             | 无论查询难易，都先执行本 Skill          |\\n|  5   | **假设用户权限**                 | \\\"管理员应该能看到所有数据\\\"                                   | 必须通过本 Skill 确认用户身份，不能假设 |\\n\\n### 1.3 强制执行检查清单\\n\\n在执行 `mcp__数据库查询` 之前，必须逐项确认：\\n\\n| 序号 | 检查项                                               | 确认状态 |\\n| :--: | ---------------------------------------------------- | :------: |\\n|  1   | 已获取当前用户的 `user_id`、`tenant_id`、`user_type` |  ✅ / ❌   |\\n|  2   | 已根据 `user_type` 确定权限过滤规则                  |  ✅ / ❌   |\\n|  3   | `user_type = 2` 时，已获取有权限的 `project_id` 列表 |  ✅ / ❌   |\\n|  4   | 权限过滤条件已准备就绪，可组合到 SQL 中              |  ✅ / ❌   |\\n|  5   | 已调用 `bims-business-query` 确认业务查询路径存在    |  ✅ / ❌   |\\n\\n', '{\"msg\":\"操作成功\",\"code\":200}', 0, NULL, '2026-07-06 02:44:04', 85);
