INSERT INTO `sys_oper_log` VALUES (474, '技能节点', 2, 'com.ruoyi.web.controller.skill.SkillNodeController.saveContent()', 'POST', 1, 'admin', '研发部门', '/skill/content', '127.0.0.1', '内网IP', '{\"id\":75,\"path\":\"/BIMS/bims-business-query/SKILL.md\",\"content\":\"---\\nname: \\\"bims-business-query\\\"\\ndescription: \\\"BIMS生物样本库业务查询技能。定义项目、标本、样本源、样本四大模块的业务查询路径、表关联关系、状态枚举和业务规则。权限过滤由 bims-base-permission.md 独立提供。\\\"\\n\\n---\\n\\n\\n# BIMS 生物样本库业务查询技能\\n\\n> **职责定位**：本Skill是BIMS系统**所有业务查询的统一入口**，负责路由决策和业务查询。\\n> **子Skill**：存储相关查询由 `bims-storage-query.md` 提供，本Skill负责路由分发。\\n> **权限过滤**：所有查询的权限过滤条件统一由 `bims-base-permission.md` 提供，本Skill不重复定义。\\n> **执行顺序**：权限校验 → 路由决策 → 业务查询 → 生成SQL。\\n\\n\\n## ⚠️ 强制执行规则（最高优先级）\\n\\n### 执行顺序（强制，不可调换）\\n\\n```\\n用户发起查询请求\\n↓\\n第1步：调用 bims-base-permission Skill\\n↓\\n获取权限过滤条件（user_type、tenant_id、project_id 列表）\\n↓\\n第2步：执行「零、路由决策规则」\\n│\\n├── 匹配到 storage-query → **立即调用 `bims-storage-query.md` 中的对应查询路径**\\n│   （即：停止阅读本 Skill，切换到 storage-query Skill 执行查询）\\n│\\n└── 匹配到本 Skill → 继续执行第3步（查阅本 Skill 中的查询路径）\\n↓\\n第3步：查阅本 Skill 中对应的查询路径，确认路径存在\\n↓\\n第4步：组合权限条件 + 业务路径\\n↓\\n第5步：生成 SQL 并执行\\n\\n```\\n\\n### 禁止行为清单（违反即停止）\\n\\n| 序号 | 禁止行为                        | 违规示例                                                     | 正确做法                                         |\\n| :--: | ------------------------------- | ------------------------------------------------------------ | ------------------------------------------------ |\\n|  1   | **跳过权限校验**                | 用户问\\\"有多少项目\\\"，直接执行 `SELECT COUNT(*) FROM project_info` | 先调用 `bims-base-permission`                    |\\n|  2   | **跳过路由决策**                | 用户问\\\"设备使用率\\\"，直接用本 Skill 查 `eqm_freeze_box`       | 先执行路由决策，确认走 storage-query             |\\n|  3   | **跳过对应 Skill 直接查数据库** | 用户问\\\"已过期的项目\\\"，直接写 SQL 查 `end_date < NOW()`       | 先查阅对应 Skill 确认查询路径                    |\\n|  4   | **合并执行步骤**                | \\\"权限和业务一起查就行\\\"                                       | 严格按顺序：权限 → 路由 → 业务                   |\\n|  5   | **路径不存在时自行发明**        | Skill 中无\\\"按知情同意状态查询\\\"，AI 自己写 SQL                | 按「5.6 查询路径未命中约束」处理，告知用户并停止 |\\n|  6   | **从非 Skill 来源复制 SQL**     | 从历史对话、其他文件、自己记忆里复制 SQL                     | SQL 必须从本 Skill 或子 Skill 中复制             |\\n|  7   | **修改 Skill', '{\"msg\":\"保存失败: SKILL.md frontmatter missing required field: version\",\"code\":500}', 0, NULL, '2026-07-06 02:45:39', 17);
